from difflib import SequenceMatcher
def lcs_ratio(a,b):
    # longest common substring length / max(len(a),len(b))
    # Using SequenceMatcher to find longest matching block
    sm = SequenceMatcher(None, a, b)
    match = sm.find_longest_match(0, len(a), 0, len(b))
    lcs_len = match.size
    if max(len(a),len(b))==0:
        return 1.0
    return lcs_len / max(len(a), len(b))

def token_f1(a,b):
    # a and b are normalized strings; tokenize by whitespace
    atoks = a.split()
    btoks = b.split()
    if not atoks or not btoks:
        return 0.0
    a_counts={}
    for t in atoks: a_counts[t]=a_counts.get(t,0)+1
    b_counts={}
    for t in btoks: b_counts[t]=b_counts.get(t,0)+1
    overlap = 0
    for t,c in a_counts.items():
        overlap += min(c, b_counts.get(t,0))
    if overlap==0:
        return 0.0
    precision = overlap / len(atoks)
    recall = overlap / len(btoks)
    f1 = 2*precision*recall/(precision+recall)
    return f1

